<script lang="ts">import {activeCells,HEIGHT,WIDTH,type BottleState} from '$lib/game/pill-bottle';export let state:BottleState;$:active=new Map(activeCells(state).map(x=>[x.row*WIDTH+x.col,x.cell]));</script>
<div class="bottle" aria-label="Pill bottle"><div class="neck"></div><div class="grid">{#each Array(WIDTH*HEIGHT) as _,i}{@const cell=active.get(i)??state.board[i]}<i class:virus={cell?.kind==='virus'} class:pill={cell?.kind==='pill'} class:cyan={cell?.color==='cyan'} class:pink={cell?.color==='pink'} class:yellow={cell?.color==='yellow'}></i>{/each}</div></div>
<style>.bottle{position:relative;width:min(27vw,180px);margin:auto}.neck{width:45%;height:10px;margin:auto;border:3px solid #606477;border-bottom:0}.grid{display:grid;grid-template-columns:repeat(8,1fr);background:#08090d;border:3px solid #606477;padding:3px;box-shadow:5px 5px 0 #050609}.grid i{aspect-ratio:1;border:1px solid #151720;border-radius:2px}.grid i.virus{border-radius:50%;border:2px solid rgba(0,0,0,.35)}.grid i.pill{border:2px outset rgba(255,255,255,.25)}.cyan{background:var(--cyan)}.pink{background:var(--pink)}.yellow{background:var(--yellow)}</style>
